1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	export function nextGeneration(cells: Cell[]): Cell[] {
10	  const key = ([x, y]: Cell): string => `${x},${y}`;
11	  const liveKeys = new Set(cells.map(key));
12	  const isAlive = (cell: Cell): boolean => liveKeys.has(key(cell));
13	
14	  const countNeighbors = ([x, y]: Cell): number =>
15	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive([x + dx, y + dy])).length;
16	
17	  const candidates = new Map<string, Cell>();
18	  for (const cell of cells) {
19	    candidates.set(key(cell), cell);
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const neighbor: Cell = [cell[0] + dx, cell[1] + dy];
22	      candidates.set(key(neighbor), neighbor);
23	    }
24	  }
25	
26	  return [...candidates.values()].filter((cell) => {
27	    const n = countNeighbors(cell);
28	    return n === 3 || (n === 2 && isAlive(cell));
29	  });
30	}
